// Proxy ComfyUI image/GIF via HTTP — serves via ngrok to Slack image blocks
const http = require('http');

const query = $input.first().json.query || {};
const filename = (query.filename || '').replace(/[^a-zA-Z0-9_\-\.]/g, '');
const subfolder = (query.subfolder || '').replace(/[^a-zA-Z0-9_\-]/g, '');
const type = (query.type || 'output').replace(/[^a-zA-Z0-9_]/g, '');

if (!filename) {
  return [{ json: { error: 'missing filename' } }];
}

const path = `/view?filename=${encodeURIComponent(filename)}&subfolder=${encodeURIComponent(subfolder)}&type=${encodeURIComponent(type)}`;

const result = await new Promise((resolve, reject) => {
  const req = http.get({ host: 'host.docker.internal', port: 8188, path }, (res) => {
    const chunks = [];
    res.on('data', c => chunks.push(c));
    res.on('end', () => {
      const buf = Buffer.concat(chunks);
      const ct = res.headers['content-type'] || 'image/png';
      const isGif = filename.endsWith('.gif') || ct.includes('gif');
      resolve({
        buf,
        mimeType: isGif ? 'image/gif' : ct.split(';')[0].trim(),
        filename
      });
    });
  });
  req.on('error', reject);
});

if (!result.buf || result.buf.length < 10) {
  return [{ json: { error: 'image not found', filename, path } }];
}

return [{
  json: { filename, size: result.buf.length },
  binary: {
    data: {
      data: result.buf.toString('base64'),
      mimeType: result.mimeType,
      fileName: result.filename,
      fileSize: result.buf.length
    }
  }
}];
